import{_ as r,c as a,o as t,a3 as l}from"./chunks/framework.YHjwC3fH.js";const u=JSON.parse('{"title":"复读公约","description":"","frontmatter":{},"headers":[],"relativePath":"guide/rules.md","filePath":"guide/rules.md"}'),o={name:"guide/rules.md"},e=l('<h1 id="复读公约" tabindex="-1">复读公约 <a class="header-anchor" href="#复读公约" aria-label="Permalink to &quot;复读公约&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">原文</p><p><a href="https://docs.qq.com/doc/DR2lsTkNNS2ZURnBW" target="_blank" rel="noreferrer">https://docs.qq.com/doc/DR2lsTkNNS2ZURnBW</a></p></div><p>以下关键词 MUST、MUST NOT、REQUIRED、SHALL、SHALL NOT、SHOULD、SHOULD NOT、 RECOMMENDED、MAY、OPTIONAL 依照 <a href="https://www.rfc-editor.org/rfc/rfc2119" target="_blank" rel="noreferrer">RFC 2119</a> 的叙述解读。</p><p>以下关键词 MUST (BUT WE KNOW YOU WON&#39;T)、SHOULD CONSIDER、REALLY SHOULD NOT、OUGHT TO、WOULD PROBABLY、MAY WISH TO、COULD、POSSIBLE、MIGHT依照 <a href="https://www.rfc-editor.org/rfc/rfc6919.html" target="_blank" rel="noreferrer">RFC 6919</a> 的叙述解读。</p><h2 id="总则" tabindex="-1">总则 <a class="header-anchor" href="#总则" aria-label="Permalink to &quot;总则&quot;">​</a></h2><ol><li><p>本公约由基岩社工具人团队编写。</p></li><li><p>任何玩家一旦进入FDCraft,则视为同意本公约。如不认可，请立即退出服务器，并在Minecraft多人游戏列表中删除本服务器的记录。</p></li><li><p>若不遵守本公约，基岩社工具人团队有权对该玩家的账号进行不同程度的封禁，包括但不限于禁止进入FDCraft下游服务器、禁止进入FDCraft所有服务器、封禁用户中心账号、联合黑名单封禁。</p></li><li><p>任何玩家有权要求基岩社工具人团队清除其在FDCraft、用户中心等服务器上的相关数据，包括但不限于账号、玩家数据、建筑。</p></li><li><p>FDCraft不适用任何现实中的社会管理或资源配置理论与概念，包括但不限于农奴制、资本主义、社会主义、共产主义。</p></li><li><p>FDCraft不喜欢规矩与约束。因此，复读公约会以高度审慎的态度进行制定。一切不必要的约定都不应该被写入本公约。</p></li><li><p>复读公约不追求成体系的、事无巨细的规范。我们相信我们的同学都是友善的。我们永远以善意对待，并以善意揣测我们的朋友们，为他们送上我们的包容。因此，我们仅基于可能遇到的问题进行一事一议式的约定。</p></li><li><p>任何人均可以批注、交流群内公开提出、私聊工具人等形式对本公约提出建议。所有的观点将会被公平地对待，并在理性的批判后被评价为合适与否。</p></li></ol><h2 id="关于服务器属性" tabindex="-1">关于服务器属性 <a class="header-anchor" href="#关于服务器属性" aria-label="Permalink to &quot;关于服务器属性&quot;">​</a></h2><ol><li>虽然FDCraft在服务器形态上与生电服务器相似，FDCraft不是<strong>生电服</strong>。FDCraft 是面向复旦大学 Minecraft 爱好者的<strong>系列多人联机服务器</strong>。</li><li>FDCraft在规则上与生电服务器完全不同，可将<a href="https://www.bilibili.com/read/cv17891731" target="_blank" rel="noreferrer">Aircraft的专栏</a>中<code>「生电服」的规则</code> 一节与复读公约进行比对。FDCraft不喜欢规矩与约束，任何<strong>不破坏他人游戏体验</strong>的行为都是被允许的。</li></ol><h2 id="关于群名片的约定" tabindex="-1">关于群名片的约定 <a class="header-anchor" href="#关于群名片的约定" aria-label="Permalink to &quot;关于群名片的约定&quot;">​</a></h2><ol><li><p>为保障玩家的利益，构建起沟通的桥梁，所有玩家 <strong>必须</strong> 在群名片中注明自己在FDCraft中的名称。</p></li><li><p>为促进交流，增进友谊，我们 <strong>建议</strong> 大家采用<code>ID-年级专业-真实姓名</code>的格式编辑自己的群名片。</p></li></ol><h2 id="关于服务器公共资源与私有资源的约定" tabindex="-1">关于服务器公共资源与私有资源的约定 <a class="header-anchor" href="#关于服务器公共资源与私有资源的约定" aria-label="Permalink to &quot;关于服务器公共资源与私有资源的约定&quot;">​</a></h2><ol><li>私人容器包括<strong>个人住宅内容器</strong>，<strong>未完成工程处容器</strong>，<strong>明显告示为私人所有的容器</strong>，<strong>无标识的既不处于私人空间也不处于公共设施处的容器</strong>。私人容器的所有者为容器所在建筑的所有者/建造者。</li><li>不符合私人容器定义的容器均属于公共容器，<strong>但属于功能性建筑的一部分、机器运行时不可或缺的特殊容器除外</strong>，包括但不限于 <strong>所有物品展示框与盔甲架</strong>、有特殊功能的漏斗/投掷器/木桶 等。</li><li>若对于建筑的属性与所有者有异议，以复读百科、旦星一号、建筑现场告示牌或基岩社工具人的判断为准。</li><li>私人容器内物品 <strong>必须</strong> 在征得所有者同意后方可取用。若物品有缺失所有者有权在群内询问或联系运维查询。所有私人物品／需要自己使用的物品均 <strong>应该</strong> 放到私人容器中。</li><li>公共容器内物品 <strong>可以</strong> 随意取用。<strong>任何玩家无权追查</strong>公共容器内物品去向及用途，取用者同样可对上述询问保持沉默。将物品放置于公共容器内意味着放弃对该物品的所有权，其将转变为公共物品，可供任何人<strong>无条件取用</strong>。</li><li><strong>滥用</strong>公共资源等情况，可向基岩社工具人团体申请仲裁。</li><li>在有明确声明（如在复读百科中注明）的情况下，以声明内容为准，不适用上述各条（如在复读百科公共设施处注明每天只允许以私人目的获取该机器生产的一半产品之类的声明）。</li></ol><h2 id="关于生电用地冲突的约定" tabindex="-1">关于生电用地冲突的约定 <a class="header-anchor" href="#关于生电用地冲突的约定" aria-label="Permalink to &quot;关于生电用地冲突的约定&quot;">​</a></h2><h3 id="功能性建筑与观赏性建筑" tabindex="-1">功能性建筑与观赏性建筑 <a class="header-anchor" href="#功能性建筑与观赏性建筑" aria-label="Permalink to &quot;功能性建筑与观赏性建筑&quot;">​</a></h3><ol><li><p>功能性建筑即传统意义上的“生电机器”，包括但不限于利用游戏机制生产物品、提供刷怪场地的建筑。</p></li><li><p>其他一切建筑均属于观赏性建筑，包括但不限于私家住宅、公共景观。</p></li><li><p>如遇冲突，则视为<strong>观赏性建筑</strong>，例如一个美丽的刷石机。</p></li><li><p>如果你的未完成的工地可能被误判为生电机器，则请在醒目的地方标注其不是功能性建筑。或者，你 <strong>可以</strong> 在沟通中与其他人明确这一点。并且，请相信工具人团队的判断。</p></li></ol><h3 id="冲突处理流程" tabindex="-1">冲突处理流程 <a class="header-anchor" href="#冲突处理流程" aria-label="Permalink to &quot;冲突处理流程&quot;">​</a></h3><ol><li><p>乙方的生电用地需求与甲方未完成的（特指基本功能未实现，不包括装饰、改进等流程未完成）生电机器发生冲突时，应当与甲方积极沟通。</p></li><li><p>若甲方明确反对，则乙方不得强制征用甲方的用地。</p></li><li><p>若甲方在一定时间内没有回应，乙方 <strong>可以</strong> 向基岩社工具人团体提交拆除申请。拆除申请提交经工具人团队审核通过后的7天内，若甲方没有明确反对，则乙方 <strong>可以</strong> 在服务器运维人员的协助下，备份甲方的机器，并在原址处拆除。</p></li></ol><h2 id="修订说明" tabindex="-1">修订说明 <a class="header-anchor" href="#修订说明" aria-label="Permalink to &quot;修订说明&quot;">​</a></h2><h3 id="_2023-6-25" tabindex="-1">2023.6.25 <a class="header-anchor" href="#_2023-6-25" aria-label="Permalink to &quot;2023.6.25&quot;">​</a></h3><ul><li>由于有玩家对于FDCraft的性质提出了疑问，增加 “服务器属性” 一节。</li></ul><h3 id="_2023-11-10" tabindex="-1">2023.11.10 <a class="header-anchor" href="#_2023-11-10" aria-label="Permalink to &quot;2023.11.10&quot;">​</a></h3><ul><li>对公约进行规范语意化。</li><li>“总则”一节中，增加 社团权力与玩家权力 条目。</li><li>“服务器属性”一节中，增加 “FDCraft不喜欢规矩与约束，任何<strong>不破坏他人游戏体验</strong>的行为都是被允许的” 条目。</li><li>由于最近各校均出现了<strong>有玩家随意取用物品展示框内物品、取用分类器内物品</strong>的现象，”关于服务器公共资源与私有资源的约定“一节中，明确 “属于功能性建筑的一部分、机器运行时不可或缺的容器” 不属于公共容器。</li></ul>',22),i=[e];function n(s,h,c,d,p,g){return t(),a("div",null,i)}const _=r(o,[["render",n]]);export{u as __pageData,_ as default};
